{
  "name": "anvil-racing-react",
  "private": true,
  "version": "1.0.0",
  "type": "module",
  "scripts": {
    "dev": "vite",
    "build": "vite build",
    "preview": "vite preview"
  },
  "dependencies": {
    "@studio-freight/lenis": "^1.0.42",
    "clsx": "^2.1.0",
    "gsap": "^3.12.5",
    "iconify-icon": "^2.1.0",
    "react": "^18.2.0",
    "react-dom": "^18.2.0"
  },
  "devDependencies": {
    "@vitejs/plugin-react": "^4.2.1",
    "autoprefixer": "^10.4.19",
    "postcss": "^8.4.38",
    "tailwindcss": "^3.4.3",
    "vite": "^5.2.8"
  }
}

import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'

export default defineConfig({
  plugins: [react()],
})

import React, { useEffect } from 'react';
import Lenis from '@studio-freight/lenis';
import gsap from 'gsap';
import ScrollTrigger from 'gsap/ScrollTrigger';

import Preloader from './components/Preloader';
import Header from './components/Header';
import Hero from './components/Hero';
import About from './components/About';
import Values from './components/Values';
import Stats from './components/Stats';
import Goal from './components/Goal';
import Showcase from './components/Showcase';
import Team from './components/Team';
import CTA from './components/CTA';
import FAQ from './components/FAQ';
import Footer from './components/Footer';

gsap.registerPlugin(ScrollTrigger);

export default function App() {
  useEffect(() => {
    // Prevent scroll until preloader hides, handled in CSS initially but ensure Lenis is smooth
    document.documentElement.style.setProperty('overflow', 'hidden', 'important');
    history.scrollRestoration = 'manual';

    const lenis = new Lenis({
      duration: 1.2,
      easing: (t) => Math.min(1, 1.001 - Math.pow(2, -10 * t)),
      smooth: true,
    });

    function raf(time) {
      lenis.raf(time);
      requestAnimationFrame(raf);
    }
    requestAnimationFrame(raf);

    // Initial GSAP reveals
    let ctx = gsap.context(() => {
      gsap.from('.about-heading-sm', { scrollTrigger: { trigger: '.about-section', start: 'top 70%' }, y: 40, opacity: 0, duration: 0.8, ease: 'power2.out' });
      gsap.from('.about-heading-lg', { scrollTrigger: { trigger: '.about-section', start: 'top 65%' }, y: 60, opacity: 0, duration: 1, ease: 'power2.out', delay: 0.2 });
      gsap.from('.about-text', { scrollTrigger: { trigger: '.about-section', start: 'top 55%' }, y: 30, opacity: 0, duration: 0.8, ease: 'power2.out', delay: 0.4 });
      gsap.from('.about-stats > div', { scrollTrigger: { trigger: '.about-stats', start: 'top 80%' }, y: 30, opacity: 0, duration: 0.6, stagger: 0.15, ease: 'power2.out' });
      gsap.from('.values-card', { scrollTrigger: { trigger: '.values-section', start: 'top 60%' }, y: 60, opacity: 0, duration: 0.8, stagger: 0.3, ease: 'power2.out' });
      gsap.from('.cta-heading', { scrollTrigger: { trigger: '.cta-section', start: 'top 60%' }, y: 60, opacity: 0, duration: 1, ease: 'power2.out' });
      gsap.from('.cta-text', { scrollTrigger: { trigger: '.cta-section', start: 'top 50%' }, y: 30, opacity: 0, duration: 0.8, ease: 'power2.out', delay: 0.3 });
      gsap.from('.btn-wrapper', { scrollTrigger: { trigger: '.cta-section', start: 'top 45%' }, y: 30, opacity: 0, duration: 0.8, ease: 'power2.out', delay: 0.5 });
      gsap.from('.team-img-wrapper', { scrollTrigger: { trigger: '.team-section', start: 'top 60%' }, x: -60, opacity: 0, duration: 1, ease: 'power2.out' });
      gsap.from('.team-right > *', { scrollTrigger: { trigger: '.team-section', start: 'top 55%' }, y: 40, opacity: 0, duration: 0.7, stagger: 0.15, ease: 'power2.out' });
    });

    return () => {
      lenis.destroy();
      ctx.revert();
    };
  }, []);

  return (
    <>
      <Preloader />
      <Header />
      <main>
        <Hero />
        <About />
        <Values />
        <Stats />
        <Goal />
        <Showcase />
        <Team />
        <CTA />
        <FAQ />
      </main>
      <Footer />
    </>
  );
}

@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  --bg: #0A0C12;
  --surface: #14181E;
  --text: #EEF2F9;
  --text-dim: #B8BCC6;
  --muted: #999EA6;
  --accent: #F90000;
  --accent-glow: rgba(249, 0, 0, 0.15);
  --border: rgba(238, 242, 249, 0.08);
  --font-heading: 'Space Grotesk', system-ui, sans-serif;
  --font-mono: 'Geist Mono', 'SF Mono', monospace;
}

*, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }
html { scrollbar-width: none; -webkit-font-smoothing: antialiased; }
html::-webkit-scrollbar { width: 0 !important; height: 0 !important; }
html.lenis { height: auto; }
.lenis.lenis-smooth { scroll-behavior: auto; }
.lenis.lenis-stopped { overflow: hidden; }

body { 
  font-family: var(--font-mono); 
  font-weight: 400; 
  color: var(--text); 
  background: var(--bg); 
  line-height: 1.5; 
  overflow-x: hidden; 
  font-size: 14px; 
}

a { color: inherit; text-decoration: none; }
img { display: block; max-width: 100%; height: auto; }
button { font: inherit; border: none; background: none; cursor: pointer; color: inherit; }

body::before { 
  content: ''; 
  position: fixed; 
  inset: 0; 
  z-index: 9999; 
  pointer-events: none; 
  opacity: 0.03; 
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E"); 
  background-repeat: repeat; 
  background-size: 256px; 
}

/* PRELOADER */
.preloader { position: fixed; inset: 0; z-index: 10000; display: flex; align-items: center; justify-content: center; background: var(--bg); backdrop-filter: blur(30px); }
.preloader-icon { position: absolute; top: 50%; left: 50%; transform: translate(-50%, -50%); width: 48px; height: 48px; }
.preloader-icon svg { width: 100%; height: 100%; }
.preloader-img-block { position: absolute; right: 32px; top: 0; height: 200%; display: flex; flex-direction: column; }
.preloader-percent { position: absolute; bottom: 32px; left: 32px; font-size: 0.75rem; font-weight: 500; letter-spacing: 0.015rem; }
.preloader .shadow-top { position: absolute; top: 0; left: 0; right: 0; height: 120px; background: linear-gradient(to bottom, var(--bg), transparent); z-index: 1; }
.preloader .shadow-bot { position: absolute; bottom: 0; left: 0; right: 0; height: 120px; background: linear-gradient(to top, var(--bg), transparent); z-index: 1; }

/* HEADER */
.header { position: fixed; top: 0; left: 0; right: 0; z-index: 100; padding: 16px 32px; display: flex; align-items: center; justify-content: space-between; }
.header-left { display: flex; align-items: center; gap: 40px; }
.header-logo { display: flex; align-items: center; gap: 10px; font-family: var(--font-heading); font-weight: 700; font-size: 1.1rem; letter-spacing: 0.08em; text-transform: uppercase; }
.header-logo-mark { width: 32px; height: 32px; background: var(--accent); display: flex; align-items: center; justify-content: center; clip-path: polygon(50% 0%, 100% 25%, 100% 75%, 50% 100%, 0% 75%, 0% 25%); }
.header-logo-mark iconify-icon { font-size: 16px; color: #fff; }
.header-nav { display: flex; gap: 24px; }
.header-nav a { font-size: 0.75rem; font-weight: 500; letter-spacing: 0.015rem; text-transform: uppercase; color: var(--muted); transition: color 0.3s ease; }
.header-nav a:hover { color: var(--text); }
.header-right { display: flex; align-items: center; gap: 20px; }
.night-mode-btn { display: flex; align-items: center; gap: 8px; font-size: 0.75rem; font-weight: 500; letter-spacing: 0.015rem; color: var(--muted); cursor: pointer; }
.plus-wrap { position: relative; width: 12px; height: 12px; }
.plus-wrap-line { position: absolute; background: var(--muted); transition: transform 0.3s ease; }
.plus-wrap-line-1 { width: 12px; height: 1px; top: 50%; left: 0; transform: translateY(-50%); }
.plus-wrap-line-2 { width: 1px; height: 12px; left: 50%; top: 0; transform: translateX(-50%) rotateZ(90deg); }
.join-btn { display: inline-flex; align-items: center; gap: 6px; padding: 6px 14px; border: 1px solid rgba(238,242,249,0.16); font-size: 0.75rem; font-weight: 500; letter-spacing: 0.015rem; text-transform: uppercase; color: var(--text); transition: all 0.3s ease; }
.join-btn:hover { border-color: var(--accent); color: var(--accent); }
.join-btn svg { width: 12px; height: 12px; }

/* HERO */
.hero-section { position: relative; width: 100%; height: 100vh; overflow: hidden; background: var(--bg); }
.hero-bg { position: absolute; inset: 0; z-index: 0; }
.hero-bg img { width: 100%; height: 100%; object-fit: cover; filter: brightness(0.75) saturate(1.1); }
.hero-bg::after { content: ''; position: absolute; inset: 0; background: linear-gradient(to bottom, rgba(10,12,18,0.1) 0%, rgba(10,12,18,0.3) 60%, var(--bg) 100%); }
.tracking-area { position: absolute; inset: 0; z-index: 5; cursor: none; }
.custom-cursor { position: absolute; pointer-events: none; z-index: 10; opacity: 0; }
.line-vertical { position: absolute; width: 1px; height: 40px; background: var(--text); left: 50%; top: -20px; transform: translateX(-50%); opacity: 0.5; }
.line-horizontal { position: absolute; width: 40px; height: 1px; background: var(--text); top: 50%; left: -20px; transform: translateY(-50%); opacity: 0.5; }
.cursor-dot { position: absolute; width: 4px; height: 4px; background: var(--accent); border-radius: 50%; top: -2px; left: -2px; }
.coords { position: absolute; top: 24px; left: 8px; font-size: 0.65rem; font-weight: 400; letter-spacing: 0.02rem; color: var(--muted); white-space: nowrap; }
.hero-wrapper { position: relative; z-index: 3; height: 100%; display: flex; flex-direction: column; justify-content: flex-end; padding: 0 32px 48px; }
.hero-bottom { display: flex; justify-content: space-between; align-items: flex-end; }
.hero-label { display: flex; align-items: center; gap: 8px; margin-bottom: 16px; }
.red-sq { width: 8px; height: 8px; background: var(--accent); animation: fadeBlink 1s linear infinite; }
@keyframes fadeBlink { 0% { opacity: 1; } 50% { opacity: 0; } 100% { opacity: 1; } }
.hero-label-text { font-size: 0.72rem; font-weight: 500; letter-spacing: 0.015rem; text-transform: uppercase; color: var(--muted); }
.hero-heading-wrapper { overflow: hidden; }
.hero-heading { font-family: var(--font-heading); font-weight: 700; font-size: clamp(3rem, 8vw, 7rem); line-height: 0.95; letter-spacing: -0.03em; text-transform: uppercase; }
.hero-heading.accent { color: var(--accent); }
.hero-heading-icon { display: inline-block; width: 0.7em; height: 0.7em; vertical-align: middle; margin-right: 0.15em; }
.scroll-indicator { display: flex; flex-direction: column; align-items: center; gap: 4px; font-size: 0.65rem; font-weight: 500; letter-spacing: 0.05em; text-transform: uppercase; color: var(--muted); }
.scroll-indicator::after { content: ''; width: 1px; height: 32px; background: linear-gradient(to bottom, var(--muted), transparent); }
.square-grid { position: absolute; inset: 0; z-index: 4; display: grid; grid-template-columns: repeat(30, 1fr); grid-template-rows: repeat(17, 1fr); pointer-events: none; }
.square { background: var(--bg); aspect-ratio: 1/1; opacity: 0; }

/* ABOUT / SPOTLIGHT */
.about-section { position: relative; min-height: 100vh; overflow: hidden; }
#spotlight-section { position: absolute; inset: 0; background-color: var(--surface); background-image: radial-gradient(circle 400px at var(--mouse-x) var(--mouse-y), rgba(255,255,255,0.12) 0%, transparent 100%); background-repeat: no-repeat; background-attachment: fixed; }
.about-bg-pattern { position: absolute; inset: 0; background-image: radial-gradient(circle 1px at center, rgba(255,255,255,0.08) 1px, transparent 1px); background-size: 24px 24px; opacity: 0.4; }
.mask-area { position: relative; z-index: 2; padding: 120px 32px; }
.about-wrapper { max-width: 1200px; margin: 0 auto; }
.section-label { display: flex; align-items: center; gap: 8px; font-size: 0.72rem; font-weight: 500; letter-spacing: 0.08em; text-transform: uppercase; color: var(--muted); margin-bottom: 48px; }
.about-heading-sm { font-family: var(--font-heading); font-weight: 400; font-size: 1.4rem; color: var(--text-dim); margin-bottom: 8px; }
.about-heading-lg { font-family: var(--font-heading); font-weight: 700; font-size: clamp(2rem, 4vw, 3.5rem); line-height: 1.1; letter-spacing: -0.02em; text-transform: uppercase; margin-bottom: 48px; }
.text-accent { color: var(--accent); }
.about-text { max-width: 520px; font-size: 0.82rem; line-height: 1.7; color: var(--text-dim); }
.about-stats { display: flex; gap: 48px; margin-top: 48px; }
.about-stat-val { font-family: var(--font-heading); font-weight: 700; font-size: 2.4rem; line-height: 1; }
.about-stat-label { font-size: 0.65rem; font-weight: 500; letter-spacing: 0.05em; text-transform: uppercase; color: var(--muted); margin-top: 4px; }
.dots { position: absolute; inset: 0; background: radial-gradient(circle, rgba(255,255,255,0.6) 2px, transparent 2px); background-size: 32px 32px; mask-image: radial-gradient(circle at var(--mx) var(--my), rgba(255,255,255,1) 0%, rgba(255,255,255,1) 10%, rgba(255,255,255,0) 16%); mask-repeat: no-repeat; opacity: 0; transition: opacity 0.3s ease; pointer-events: none; }
#cursor-main { width: 390px; height: 390px; position: absolute; border-radius: 50%; pointer-events: none; background: radial-gradient(circle, rgba(249,0,0,0.3) 0%, rgba(249,0,0,0.1) 20%, rgba(249,0,0,0) 60%); filter: blur(1px); transform: translate(-50%,-50%); transition: left 0.1s ease-out, top 0.1s ease-out; }
.trail { width: 390px; height: 390px; position: absolute; border-radius: 50%; pointer-events: none; background: radial-gradient(circle, rgba(249,0,0,0.2) 0%, rgba(249,0,0,0.1) 20%, rgba(249,0,0,0) 60%); filter: blur(1px); transform: translate(-50%,-50%); transition: transform 0.7s ease-out, opacity 0.7s ease-out; }

/* VALUES */
.values-section { position: relative; padding: 120px 32px; background: var(--bg); }
.values-wrapper { max-width: 1200px; margin: 0 auto; display: grid; grid-template-columns: 1fr 1fr; gap: 80px; }
.values-left-heading { font-family: var(--font-heading); font-weight: 300; font-size: clamp(2rem, 3.5vw, 3rem); line-height: 1.2; letter-spacing: -0.02em; }
.values-right { display: flex; flex-direction: column; gap: 80px; }
.values-card-num { font-size: 0.72rem; font-weight: 500; letter-spacing: 0.05em; color: var(--muted); margin-bottom: 16px; }
.values-card h3 { font-family: var(--font-heading); font-weight: 600; font-size: 1.6rem; text-transform: uppercase; letter-spacing: -0.01em; margin-bottom: 12px; }
.values-card p { font-size: 0.82rem; line-height: 1.7; color: var(--text-dim); max-width: 420px; }
.values-card-img { width: 100%; max-width: 420px; margin-top: 24px; border-radius: 4px; overflow: hidden; position: relative; }
.values-card-img img { width: 100%; height: auto; filter: saturate(0.8) contrast(1.1); }
.values-card-img::after { content: ''; position: absolute; bottom: 0; left: 0; right: 0; height: 40%; background: linear-gradient(to bottom, transparent, var(--bg)); }
.red-flow { opacity: 0; transition: opacity 0.3s ease; }

/* GOAL */
.goal-section { position: relative; height: 100vh; display: flex; align-items: center; justify-content: center; overflow: hidden; background: var(--bg); }
.goal-heading-block { text-align: center; position: relative; }
.goal-word { font-family: var(--font-heading); font-weight: 700; font-size: clamp(4rem, 12vw, 10rem); line-height: 0.95; letter-spacing: -0.04em; text-transform: uppercase; display: block; opacity: 0; transform: translateY(60px); transition: all 0.8s cubic-bezier(0.215, 0.61, 0.355, 1); }
.goal-word.visible { opacity: 1; transform: translateY(0); }
.goal-word.accent-word { color: var(--accent); }
.goal-crosshair { position: absolute; top: 50%; left: 50%; transform: translate(-50%,-50%); width: 120px; height: 120px; opacity: 0; transition: opacity 1s cubic-bezier(0.215, 0.61, 0.355, 1); pointer-events: none; }
.goal-crosshair.visible { opacity: 1; }
.goal-crosshair-line { position: absolute; background: var(--accent); }
.goal-crosshair-line.h { width: 100%; height: 1px; top: 50%; transform: translateY(-50%); }
.goal-crosshair-line.v { width: 1px; height: 100%; left: 50%; transform: translateX(-50%); }
.goal-sub { position: absolute; bottom: -60px; left: 50%; transform: translateX(-50%); display: flex; align-items: center; gap: 8px; white-space: nowrap; }
.goal-sub-text { font-size: 0.72rem; font-weight: 500; letter-spacing: 0.05em; text-transform: uppercase; color: var(--text-dim); }

/* SHOWCASE */
.showcase-section { position: relative; height: 100vh; overflow: hidden; background: var(--surface); }
.showcase-img { position: absolute; inset: 0; }
.showcase-img img { width: 100%; height: 100%; object-fit: cover; filter: brightness(0.6) saturate(0.7); }
.showcase-img::after { content: ''; position: absolute; inset: 0; background: radial-gradient(ellipse at center, transparent 30%, var(--surface) 80%); }
.showcase-overlay { position: relative; z-index: 2; height: 100%; display: flex; flex-direction: column; justify-content: center; padding: 0 32px; }
.showcase-crosshair { position: absolute; top: 50%; left: 50%; transform: translate(-50%,-50%); z-index: 3; width: 80vw; height: 60vh; }
.showcase-crosshair-line-h, .showcase-crosshair-line-v { position: absolute; background: rgba(238,242,249,0.3); transition: all 1s cubic-bezier(0.215, 0.61, 0.355, 1); }
.showcase-crosshair-line-h { height: 1px; width: 0; top: 50%; left: 50%; transform: translate(-50%,-50%); }
.showcase-crosshair-line-v { width: 1px; height: 0; left: 50%; top: 50%; transform: translate(-50%,-50%); }
.showcase-crosshair.visible .showcase-crosshair-line-h { width: 100%; }
.showcase-crosshair.visible .showcase-crosshair-line-v { height: 100%; }
.showcase-info { display: flex; justify-content: space-between; max-width: 1200px; margin: 0 auto; width: 100%; }
.showcase-info-block { opacity: 0; transform: translateY(40px); transition: all 0.6s cubic-bezier(0.215, 0.61, 0.355, 1); }
.showcase-info-block.visible { opacity: 1; transform: translateY(0); }
.showcase-info-title { font-size: 1.1rem; font-weight: 600; text-transform: uppercase; letter-spacing: 0.02em; margin-bottom: 4px; }
.showcase-info-desc { font-size: 0.72rem; color: var(--muted); line-height: 1.6; }
.showcase-info-num { font-size: 0.65rem; color: var(--muted); margin-top: 8px; }

/* TEAM / MARQUEE */
.team-section { position: relative; padding: 120px 32px 0; background: var(--bg); overflow: hidden; }
.team-content { max-width: 1200px; margin: 0 auto; display: grid; grid-template-columns: 1fr 1fr; gap: 60px; align-items: start; }
.team-img-wrapper { position: relative; border-radius: 4px; overflow: hidden; }
.team-img-wrapper img { width: 100%; height: auto; filter: saturate(0.8) contrast(1.05); }
.team-img-wrapper::after { content: ''; position: absolute; bottom: 0; left: 0; right: 0; height: 40%; background: linear-gradient(to bottom, transparent, var(--bg)); }
.team-right h3 { font-family: var(--font-heading); font-weight: 700; font-size: 1.8rem; text-transform: uppercase; letter-spacing: -0.01em; margin-bottom: 20px; }
.team-right p { font-size: 0.82rem; line-height: 1.7; color: var(--text-dim); margin-bottom: 16px; }
.marquee-wrapper { position: relative; width: 100%; overflow: hidden; padding: 40px 0; margin-top: 80px; border-top: 1px solid var(--border); border-bottom: 1px solid var(--border); }
.marquee-track { display: flex; flex-wrap: nowrap; will-change: transform; }
.marquee-item { flex: 0 0 auto; display: flex; align-items: center; gap: 32px; padding: 0 32px; font-family: var(--font-heading); font-weight: 600; font-size: clamp(1.2rem, 2.5vw, 2rem); text-transform: uppercase; letter-spacing: -0.01em; white-space: nowrap; }
.marquee-item .sep { display: inline-block; width: 8px; height: 8px; background: var(--accent); flex-shrink: 0; }
.marquee-item .ghost { color: rgba(238,242,249,0.15); -webkit-text-stroke: 1px rgba(238,242,249,0.15); }

/* CTA */
.cta-section { position: relative; padding: 160px 32px; background: var(--bg); text-align: center; overflow: hidden; }
.cta-heading { font-family: var(--font-heading); font-weight: 700; font-size: clamp(2.5rem, 6vw, 5rem); line-height: 1; letter-spacing: -0.03em; text-transform: uppercase; margin-bottom: 32px; }
.cta-text { font-size: 0.82rem; color: var(--text-dim); margin-bottom: 40px; max-width: 480px; margin-left: auto; margin-right: auto; line-height: 1.7; }
.btn-wrapper { display: flex; justify-content: center; gap: 16px; }
.cta-btn { display: flex; align-items: center; justify-content: center; padding: 12px 32px; border: 1px solid var(--surface); font-family: var(--font-mono); font-size: 0.75rem; font-weight: 500; letter-spacing: 0.015rem; text-transform: uppercase; cursor: pointer; overflow: hidden; transform-origin: center; }
.cta-btn .button-text { display: inline-block; transform-origin: center; }
.cta-filler { position: absolute; bottom: 0; left: 0; right: 0; height: 1px; background: linear-gradient(90deg, transparent, rgba(249,0,0,0.3), transparent); }

/* FAQ */
.faq-section { position: relative; padding: 120px 32px; background: var(--surface); }
.faq-wrapper { max-width: 800px; margin: 0 auto; }
.faq-header { margin-bottom: 60px; }
.faq-header h2 { font-family: var(--font-heading); font-weight: 700; font-size: 2.4rem; text-transform: uppercase; letter-spacing: -0.02em; }
.faq-item { border-top: 1px solid var(--border); cursor: pointer; }
.faq-item:last-child { border-bottom: 1px solid var(--border); }
.faq-question { display: flex; justify-content: space-between; align-items: center; padding: 20px 0; font-size: 0.88rem; font-weight: 500; letter-spacing: 0.01em; transition: color 0.3s ease; }
.faq-item:hover .faq-question { color: var(--accent); }
.faq-toggle { width: 20px; height: 20px; position: relative; flex-shrink: 0; }
.faq-toggle::before, .faq-toggle::after { content: ''; position: absolute; background: var(--text); transition: transform 0.3s ease; }
.faq-toggle::before { width: 12px; height: 1px; top: 50%; left: 50%; transform: translate(-50%,-50%); }
.faq-toggle::after { width: 1px; height: 12px; top: 50%; left: 50%; transform: translate(-50%,-50%); }
.faq-item.open .faq-toggle::after { transform: translate(-50%,-50%) rotate(90deg); }
.faq-answer { max-height: 0; overflow: hidden; transition: max-height 0.4s cubic-bezier(0.215, 0.61, 0.355, 1); }
