    a.addEventListener('mousemove', onMove);
    ac();

    return () => {
      a.removeEventListener('mouseenter', onEnter);
      a.removeEventListener('mouseleave', onLeave);
      a.removeEventListener('mousemove', onMove);
      clearTimeout(it);
      cancelAnimationFrame(rafId);
